mapper.select:
SELECT n.id, n.user_id, n.title, n.cover_image, n.scenic_id, n.like_count, n.status, n.create_time, u.nickname AS author_nickname, u.avatar AS author_avatar, (SELECT COUNT(*) > 0 FROM note_like nl WHERE nl.note_id = n.id AND nl.user_id = #{userId} AND nl.is_deleted = 0) AS liked FROM travel_note n LEFT JOIN user u ON n.user_id = u.id AND u.is_deleted = 0
n.is_deleted = 0 AND n.status = 1
AND n.title LIKE CONCAT('%', #{dto.keyword}, '%')
AND n.scenic_id = #{dto.scenicId}
AND n.user_id = #{dto.userId}
ORDER BY n.create_time DESC
